patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 659b4c30a58a..afb5c2698486 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -1532,6 +1532,7 @@ public:
   /// Returns true if \p Op should be considered invariant and if it is
   /// trivially hoistable.
   bool shouldConsiderInvariant(Value *Op);
+  bool shouldConsiderInvariantImpl(Value *Op, SmallPtrSetImpl<Value *> &Visited);

 private:
   unsigned NumPredStores = 0;
@@ -6384,16 +6385,6 @@ void LoopVectorizationCostModel::setVectorizedCallDecision(ElementCount VF) {
   }
 }

-bool LoopVectorizationCostModel::shouldConsiderInvariant(Value *Op) {
-  if (!Legal->isInvariant(Op))
-    return false;
-  // Consider Op invariant, if it or its operands aren't predicated
-  // instruction in the loop. In that case, it is not trivially hoistable.
-  return !isa<Instruction>(Op) || !TheLoop->contains(cast<Instruction>(Op)) ||
-         (!isPredicatedInst(cast<Instruction>(Op)) &&
-          all_of(cast<Instruction>(Op)->operands(),
-                 [this](Value *Op) { return shouldConsiderInvariant(Op); }));
-}

 InstructionCost
 LoopVectorizationCostModel::getInstructionCost(Instruction *I,
@@ -10477,3 +10468,31 @@ void LoopVectorizePass::printPipeline(
   OS << (VectorizeOnlyWhenForced ? "" : "no-") << "vectorize-forced-only;";
   OS << '>';
 }
+bool LoopVectorizationCostModel::shouldConsiderInvariant(Value *Op) {
+  SmallPtrSet<Value *, 8> Visited;
+  return shouldConsiderInvariantImpl(Op, Visited);
+}
+
+bool LoopVectorizationCostModel::shouldConsiderInvariantImpl(Value *Op, SmallPtrSetImpl<Value *> &Visited) {
+  if (!Legal->isInvariant(Op))
+    return false;
+  // Consider Op invariant, if it or its operands aren't predicated
+  // instruction in the loop. In that case, it is not trivially hoistable.
+  if (!isa<Instruction>(Op) || !TheLoop->contains(cast<Instruction>(Op)))
+    return true;
+  
+  Instruction *I = cast<Instruction>(Op);
+  if (isPredicatedInst(I))
+    return false;
+    
+  // Check for cycles
+  if (Visited.count(Op))
+    return true; // Assume it's safe to avoid infinite recursion
+  
+  Visited.insert(Op);
+  bool Result = all_of(I->operands(), [this, &Visited](Value *Operand) {
+    return shouldConsiderInvariantImpl(Operand, Visited);
+  });
+  Visited.erase(Op);
+  return Result;
+}

